// Precompute the Kaomoji Maker's per-slot galleries at build time, so the client
// ships only the small curated result (~130 entries) instead of the full raw
// partsInventory/partsPairs (~580 entries, ~78% of which the curation discards).
// Reads the auto-generated src/data/parts.js and writes src/data/galleries.js.
// Run: node scripts/build-galleries.mjs   (also runs from .githooks/pre-commit)
//
// The curation rules live here (build-only): a cleanliness filter (single grapheme
// or a small multi-glyph allowlist), per-slot frequency thresholds + caps, a
// curated bracket set + decoration allowlist, and the mouth→mood map. The runtime
// engine (src/lib/generator.js) just consumes the result.
import fs from "node:fs";
import { partsInventory, partsPairs } from "../src/data/parts.js";

const MULTI_ALLOW = new Set(["‿‿", "͡°"]);
const isClean = (g) => typeof g === "string" && g.length > 0 && ([...g].length === 1 || MULTI_ALLOW.has(g));

const curatePairs = (arr, { min, cap }) =>
  arr
    .filter((p) => p.count >= min && isClean(p.left) && isClean(p.right))
    .slice(0, cap)
    .map((p) => ({ left: p.left, right: p.right, identical: p.left === p.right, count: p.count }));

const curateSingles = (arr, { min, cap, block = new Set() }) =>
  arr.filter((x) => x.count >= min && isClean(x.glyph) && !block.has(x.glyph)).slice(0, cap);

// Mouth → mood: the strongest emotion lever. Groups the mouth gallery / biases 🎲.
const MOOD = {
  "▽": "happy", "∀": "happy", "◡": "happy", "‿": "happy", "ᴗ": "happy", "ᵕ": "happy", "ヮ": "happy", "ᗜ": "happy", "‿‿": "happy", "◇": "happy",
  "ω": "cute", "³": "cute", "꒳": "cute",
  "﹏": "sad", "︶": "sad", "‸": "sad", "⌓": "sad",
  "益": "angry", "Д": "angry", "д": "angry", "ヘ": "angry",
  "o": "surprised", "O": "surprised", "0": "surprised", "ロ": "surprised", "□": "surprised",
  "ε": "love",
  "ᴥ": "animal", "ﻌ": "animal", "㉨": "animal", "ェ": "animal", "ᆺ": "animal", "⩊": "animal",
  "_": "neutral", "ー": "neutral", "￣": "neutral", "∇": "neutral",
};

// Brackets are a tiny curated set so mismatched parser pairs can't leak in; each
// keeps its observed count so 🎲 weights toward the corpus-dominant round ().
const BRACKET_PAIRS = [["(", ")"], ["ʕ", "ʔ"], ["（", "）"], ["꒰", "꒱"], ["₍", "₎"]];
const bracketCount = (l, r) => partsPairs.bracket.find((p) => p.left === l && p.right === r)?.count || 1;

// Decorations: the observed-pair data is too sparse, so curate a clean set of
// symmetric flourishes (placed on both sides).
const DECOR_GLYPHS = ["☆", "★", "✧", "✦", "♡", "♥", "❤", "♪", "♬", "✿", "❀", "°", "｡", "～"];

// Optional slots lead with the null "none" entry so it's always visible.
const galleries = {
  eye: curatePairs(partsPairs.eye, { min: 3, cap: 40 }),
  mouth: curateSingles(partsInventory.mouth, { min: 2, cap: 40 }).map((m) => ({ ...m, mood: MOOD[m.glyph] || "other" })),
  bracket: [null, ...BRACKET_PAIRS.map(([left, right]) => ({ left, right, count: bracketCount(left, right) }))],
  arm: [null, ...curatePairs(partsPairs.arm, { min: 3, cap: 24 })],
  cheek: [null, ...curateSingles(partsInventory.cheek, { min: 2, cap: 14, block: new Set(["="]) })],
  decoration: [null, ...DECOR_GLYPHS.map((g) => ({ left: g, right: g, identical: true }))],
};

const header =
  "// AUTO-GENERATED by scripts/build-galleries.mjs — do not edit by hand.\n" +
  "// Curated per-slot part galleries for the Kaomoji Maker (src/lib/generator.js).\n\n";

fs.writeFileSync("src/data/galleries.js", header + "export const galleries = " + JSON.stringify(galleries, null, 2) + ";\n");

const n = Object.fromEntries(Object.entries(galleries).map(([k, v]) => [k, v.length]));
console.log("Wrote src/data/galleries.js —", JSON.stringify(n));
